        log = self.query_one(RichLog)
        log.write(
            f"[dim]Chat started with [bold]{self._model}[/bold]. "
            "Type a message and press Enter.[/dim]\n"
        )
        self.query_one(Input).focus()

    @on(Input.Submitted)
    def on_input_submitted(self, event: Input.Submitted) -> None:
        text = event.value.strip()
        if not text:
            return
        event.input.clear()

        log = self.query_one(RichLog)
        log.write(f"\n[bold blue]You:[/bold blue] {text}\n")

        self._history.append({"role": "user", "content": text})
        self._stream_response(list(self._history))

    def action_clear_history(self) -> None:
        self._history.clear()
        self._chat_id = None
        self.query_one(RichLog).clear()
        self.query_one(RichLog).write("[dim]History cleared.[/dim]\n")

    @work(exclusive=False)
    async def _stream_response(self, messages: list[dict]) -> None:
        log = self.query_one(RichLog)
        log.write(f"\n[bold green][{self._model}][/bold green] ")

        full_text = ""
        try:
            async for chunk in self._api.async_chat_stream(
                model=self._model,
                messages=messages,
                chat_id=self._chat_id,
            ):
                log.write(chunk, expand=False)
                full_text += chunk
        except APIError as exc:
            log.write(f"\n[red]Error:[/red] {exc}\n")
            self._history.pop()  # remove user message that failed
            return
        except Exception as exc:
            log.write(f"\n[red]Unexpected error:[/red] {exc}\n")
            self._history.pop()
            return

        log.write("\n")
        if full_text:
            self._history.append({"role": "assistant", "content": full_text})


