"""Textual-based interactive TUI for FactoryMind AI.

Launch with: fmind tui  (or just: fmind  when already logged in)
"""

from __future__ import annotations

from typing import ClassVar, Optional

from textual import on, work
from textual.app import App, ComposeResult
from textual.binding import Binding
from textual.containers import Container, Horizontal, Vertical
from textual.screen import Screen
from textual.widgets import (
    DataTable,
    Footer,
    Header,
    Input,
    Label,
    ListItem,
    ListView,
    RichLog,
    Static,
)

from client import config as cfg
from client.api import APIClient, APIError, get_client


# ── Helpers ────────────────────────────────────────────────────────────────────

def _make_client() -> Optional[APIClient]:
    try:
        return get_client()
    except APIError:
        return None


# ── Model Select Screen ────────────────────────────────────────────────────────

class ModelSelectScreen(Screen):
    """Pick a default model from the server catalog."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("escape", "app.pop_screen", "Back"),
    ]

    CSS = """
    ModelSelectScreen {
        align: center middle;
    }
    #model-table {
        width: 80;
        height: auto;
        border: solid $primary;
    }
    #model-hint {
        color: $text-muted;
        text-align: center;
        margin-top: 1;
    }
    """

    def __init__(self, api: APIClient) -> None:
        super().__init__()
        self._api = api

    def compose(self) -> ComposeResult:
        yield Header(show_clock=False)
        with Vertical():
            yield DataTable(id="model-table", cursor_type="row")
            yield Static("Enter to select · Esc to go back", id="model-hint")
        yield Footer()

    def on_mount(self) -> None:
        table = self.query_one(DataTable)
        table.add_columns("Model", "Description", "Cached", "Loaded")
        self._load_models()

    @work(thread=True)
    def _load_models(self) -> None:
        try:
            models = self._api.list_models()
        except APIError:
            models = []
        self.call_from_thread(self._populate_table, models)

    def _populate_table(self, models: list[dict]) -> None:
        table = self.query_one(DataTable)
        table.clear()
        for m in models:
            table.add_row(
                m["id"],
                m.get("description", ""),
                "✓" if m.get("cached") else "–",
                "● loaded" if m.get("loaded") else "○",
                key=m["id"],
            )

    @on(DataTable.RowSelected)
    def row_selected(self, event: DataTable.RowSelected) -> None:
        model_id = str(event.row_key.value)
        cfg.save_default_model(model_id)
        self.app.pop_screen()
        self.app.notify(f"Default model set to {model_id}", title="Model selected")


# ── Chat Screen ────────────────────────────────────────────────────────────────

class ChatScreen(Screen):
    """Full interactive chat with streaming responses."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("ctrl+c", "app.pop_screen", "Back", show=False),
        Binding("escape", "app.pop_screen", "Back"),
        Binding("ctrl+l", "clear_history", "Clear"),
    ]

    CSS = """
    ChatScreen {
        layout: vertical;
    }
    #messages {
        height: 1fr;
        border: solid $primary;
        overflow-y: auto;
        padding: 0 1;
    }
    #input-row {
        height: 3;
        layout: horizontal;
    }
    #chat-input {
        width: 1fr;
    }
    #model-label {
        color: $success;
        padding: 0 1;
        content-align: center middle;
        height: 3;
    }
    """

    def __init__(self, api: APIClient, model: str) -> None:
        super().__init__()
        self._api = api
        self._model = model
        self._history: list[dict] = []
        self._chat_id: Optional[str] = None

    def compose(self) -> ComposeResult:
        yield Header(show_clock=True)
        yield RichLog(id="messages", highlight=True, markup=True, wrap=True)
        with Horizontal(id="input-row"):
            yield Label(f"[{self._model}]", id="model-label")
            yield Input(placeholder="Type a message… (Esc = back)", id="chat-input")
        yield Footer()

    def on_mount(self) -> None:
        log = self.query_one(RichLog)
        log.write(
            f"[dim]Chat started with [bold]{self._model}[/bold]. "
            "Type a message and press Enter.[/dim]\n"
        )
        self.query_one(Input).focus()

    @on(Input.Submitted)
    def on_input_submitted(self, event: Input.Submitted) -> None:
        text = event.value.strip()
        if not text:
            return
        event.input.clear()

        log = self.query_one(RichLog)
        log.write(f"\n[bold blue]You:[/bold blue] {text}\n")

        self._history.append({"role": "user", "content": text})
        self._stream_response(list(self._history))

    def action_clear_history(self) -> None:
        self._history.clear()
        self._chat_id = None
        self.query_one(RichLog).clear()
        self.query_one(RichLog).write("[dim]History cleared.[/dim]\n")

    @work(exclusive=False)
    async def _stream_response(self, messages: list[dict]) -> None:
        log = self.query_one(RichLog)
        log.write(f"\n[bold green][{self._model}][/bold green] ")

        full_text = ""
        try:
            async for chunk in self._api.async_chat_stream(
                model=self._model,
                messages=messages,
                chat_id=self._chat_id,
            ):
                log.write(chunk, expand=False)
                full_text += chunk
        except APIError as exc:
            self._history.pop()  # remove the user message that failed
            if exc.status_code == 403:
                log.write(
                    "\n[bold yellow]⚠ Session expired[/bold yellow] – "
                    "the server rejected your API key.\n"
                    "Exit the TUI and run [bold]fmind login[/bold] to authenticate again.\n"
                )
                self.app.notify(
                    "Your API key was rejected (403). Exit and run 'fmind login'.",
                    title="Session Expired",
                    severity="error",
                    timeout=0,
                )
                self.query_one(Input).disabled = True
            else:
                log.write(f"\n[red]Error {exc.status_code}:[/red] {exc}\n")
            return
        except Exception as exc:
            log.write(f"\n[red]Unexpected error:[/red] {exc}\n")
            self._history.pop()
            return

        log.write("\n")
        if full_text:
            self._history.append({"role": "assistant", "content": full_text})


# ── Main Menu Screen ───────────────────────────────────────────────────────────

class MainMenuScreen(Screen):
    """Arrow-key navigation main menu."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("q", "app.quit", "Quit"),
    ]

    CSS = """
    MainMenuScreen {
        align: center middle;
    }
    #menu-container {
        width: 52;
        height: auto;
        border: double $primary;
        padding: 1 2;
    }
    #welcome {
        text-align: center;
        color: $primary;
        text-style: bold;
        margin-bottom: 1;
    }
    #server-info {
        text-align: center;
        color: $text-muted;
        margin-bottom: 1;
    }
    ListView {
        height: auto;
        border: none;
    }
    ListItem {
        padding: 0 1;
    }
    ListItem:hover {
        background: $primary 20%;
    }
    ListItem.--highlight {
        background: $primary 30%;
    }
    """

    MENU: ClassVar[list[tuple[str, str]]] = [
        ("💬  Chat with AI", "chat"),
        ("🤖  Select Model", "models"),
        ("📜  Chat History", "history"),
        ("👤  Account", "account"),
        ("🔐  Logout", "logout"),
        ("❌  Exit", "exit"),
    ]

    def __init__(self, api: APIClient, username: str) -> None:
        super().__init__()
        self._api = api
        self._username = username

    def compose(self) -> ComposeResult:
        server = cfg.get_server_url() or ""
        model = cfg.get_default_model() or "–"
        with Container(id="menu-container"):
            yield Static("FactoryMind AI", id="welcome")
            yield Static(
                f"[dim]{self._username} @ {server}\nModel: {model}[/dim]",
                id="server-info",
            )
            yield ListView(
                *[ListItem(Label(label), id=action) for label, action in self.MENU]
            )
        yield Footer()

    def on_mount(self) -> None:
        self.query_one(ListView).focus()

    @on(ListView.Selected)
    def menu_selected(self, event: ListView.Selected) -> None:
        action = event.item.id
        if action == "exit":
            self.app.exit()
        elif action == "logout":
            cfg.clear_credentials()
            self.app.exit()
            from rich.console import Console
            Console().print("[yellow]Logged out.[/yellow]")
        elif action == "chat":
            model = cfg.get_default_model() or "Llama-2-7b-chat-hf"
            self.app.push_screen(ChatScreen(self._api, model))
        elif action == "models":
            self.app.push_screen(ModelSelectScreen(self._api))
        elif action == "history":
            self.app.push_screen(HistoryListScreen(self._api))
        elif action == "account":
            self._show_account()

    def _show_account(self) -> None:
        try:
            user = self._api.whoami()
            self.app.notify(
                f"User: {user['username']}\nEmail: {user['email']}\n"
                f"Key: {user['api_key'][:12]}…",
                title="Account",
                timeout=8,
            )
        except APIError as exc:
            self.app.notify(str(exc), title="Error", severity="error")


# ── History List Screen ────────────────────────────────────────────────────────

class HistoryListScreen(Screen):
    """Browse recent chat sessions."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("escape", "app.pop_screen", "Back"),
    ]

    CSS = """
    HistoryListScreen {
        align: center middle;
    }
    #hist-table {
        width: 90;
        height: 30;
        border: solid $primary;
    }
    #hist-hint {
        color: $text-muted;
        text-align: center;
        margin-top: 1;
    }
    """

    def __init__(self, api: APIClient) -> None:
        super().__init__()
        self._api = api

    def compose(self) -> ComposeResult:
        yield Header(show_clock=False)
        with Vertical():
            yield DataTable(id="hist-table", cursor_type="row")
            yield Static("Esc to go back", id="hist-hint")
        yield Footer()

    def on_mount(self) -> None:
        table = self.query_one(DataTable)
        table.add_columns("ID", "Title", "Model", "Updated")
        self._load_history()

    @work(thread=True)
    def _load_history(self) -> None:
        try:
            sessions = self._api.list_history(limit=30)
        except APIError:
            sessions = []
        self.call_from_thread(self._populate, sessions)

    def _populate(self, sessions: list[dict]) -> None:
        table = self.query_one(DataTable)
        table.clear()
        for s in sessions:
            updated = s["updated_at"][:16].replace("T", " ")
            table.add_row(
                s["id"][:8] + "…",
                s["title"],
                s["model_used"],
                updated,
                key=s["id"],
            )


# ── App ────────────────────────────────────────────────────────────────────────

class FactoryMindTUI(App):
    """Root Textual application."""

    TITLE = "FactoryMind AI"
    CSS = """
    Screen {
        background: $surface;
    }
    """

    def __init__(self, api: APIClient, username: str) -> None:
        super().__init__()
        self._api = api
        self._username = username

    def on_mount(self) -> None:
        self.push_screen(MainMenuScreen(self._api, self._username))


def launch_tui() -> None:
    """Entry point – build API client then start the TUI."""
    api = _make_client()
    if api is None:
        from rich.console import Console
        Console().print(
            "[red]Not logged in.[/red] Run [bold]fmind login[/bold] first."
        )
        return

    from rich.console import Console as _Console
    _con = _Console()

    try:
        user = api.whoami()
    except APIError as exc:
        if exc.status_code == 403:
            _con.print(
                "[bold yellow]⚠  Session expired[/bold yellow] – "
                "the server rejected your stored API key.\n"
                "Run [bold]fmind login[/bold] to authenticate again."
            )
        else:
            _con.print(f"[red]Cannot reach server:[/red] {exc}")
        return

    username = user.get("username", "unknown")
    FactoryMindTUI(api, username).run()

"""Textual-based interactive TUI for FactoryMind AI.

Launch with: fmind tui  (or just: fmind  when already logged in)
"""

from __future__ import annotations

from typing import ClassVar, Optional

from textual import on, work
from textual.app import App, ComposeResult
from textual.binding import Binding
from textual.containers import Container, Horizontal, Vertical
from textual.screen import Screen
from textual.widgets import (
    DataTable,
    Footer,
    Header,
    Input,
    Label,
    ListItem,
    ListView,
    RichLog,
    Static,
)

from client import config as cfg
from client.api import APIClient, APIError, get_client


# ── Helpers ────────────────────────────────────────────────────────────────────

def _make_client() -> Optional[APIClient]:
    try:
        return get_client()
    except APIError:
        return None


# ── Model Select Screen ────────────────────────────────────────────────────────

class ModelSelectScreen(Screen):
    """Pick a default model from the server catalog."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("escape", "app.pop_screen", "Back"),
    ]

    CSS = """
    ModelSelectScreen {
        align: center middle;
    }
    #model-table {
        width: 80;
        height: auto;
        border: solid $primary;
    }
    #model-hint {
        color: $text-muted;
        text-align: center;
        margin-top: 1;
    }
    """

    def __init__(self, api: APIClient) -> None:
        super().__init__()
        self._api = api

    def compose(self) -> ComposeResult:
        yield Header(show_clock=False)
        with Vertical():
            yield DataTable(id="model-table", cursor_type="row")
            yield Static("Enter to select · Esc to go back", id="model-hint")
        yield Footer()

    def on_mount(self) -> None:
        table = self.query_one(DataTable)
        table.add_columns("Model", "Description", "Cached", "Loaded")
        self._load_models()

    @work(thread=True)
    def _load_models(self) -> None:
        try:
            models = self._api.list_models()
        except APIError:
            models = []
        self.app.call_from_thread(self._populate_table, models)

    def _populate_table(self, models: list[dict]) -> None:
        table = self.query_one(DataTable)
        table.clear()
        for m in models:
            table.add_row(
                m["id"],
                m.get("description", ""),
                "✓" if m.get("cached") else "–",
                "● loaded" if m.get("loaded") else "○",
                key=m["id"],
            )

    @on(DataTable.RowSelected)
    def row_selected(self, event: DataTable.RowSelected) -> None:
        model_id = str(event.row_key.value)
        cfg.save_default_model(model_id)
        self.app.pop_screen()
        self.app.notify(f"Default model set to {model_id}", title="Model selected")


# ── Chat Screen ────────────────────────────────────────────────────────────────

class ChatScreen(Screen):
    """Full interactive chat with streaming responses."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("ctrl+c", "app.pop_screen", "Back", show=False),
        Binding("escape", "app.pop_screen", "Back"),
        Binding("ctrl+l", "clear_history", "Clear"),
    ]

    CSS = """
    ChatScreen {
        layout: vertical;
    }
    #messages {
        height: 1fr;
        border: solid $primary;
        overflow-y: auto;
        padding: 0 1;
    }
    #input-row {
        height: 3;
        layout: horizontal;
    }
    #chat-input {
        width: 1fr;
    }
    #model-label {
        color: $success;
        padding: 0 1;
        content-align: center middle;
        height: 3;
    }
    """

    def __init__(self, api: APIClient, model: str) -> None:
        super().__init__()
        self._api = api
        self._model = model
        self._history: list[dict] = []
        self._chat_id: Optional[str] = None

    def compose(self) -> ComposeResult:
        yield Header(show_clock=True)
        yield RichLog(id="messages", highlight=True, markup=True, wrap=True)
        with Horizontal(id="input-row"):
            yield Label(f"[{self._model}]", id="model-label")
            yield Input(placeholder="Type a message… (Esc = back)", id="chat-input")
        yield Footer()

    def on_mount(self) -> None:
        log = self.query_one(RichLog)
        log.write(
            f"[dim]Chat started with [bold]{self._model}[/bold]. "
            "Type a message and press Enter.[/dim]\n"
        )
        self.query_one(Input).focus()

    @on(Input.Submitted)
    def on_input_submitted(self, event: Input.Submitted) -> None:
        text = event.value.strip()
        if not text:
            return
        event.input.clear()

        log = self.query_one(RichLog)
        log.write(f"\n[bold blue]You:[/bold blue] {text}\n")

        self._history.append({"role": "user", "content": text})
        self._stream_response(list(self._history))

    def action_clear_history(self) -> None:
        self._history.clear()
        self._chat_id = None
        self.query_one(RichLog).clear()
        self.query_one(RichLog).write("[dim]History cleared.[/dim]\n")

    @work(exclusive=False)
    async def _stream_response(self, messages: list[dict]) -> None:
        log = self.query_one(RichLog)
        log.write(f"\n[bold green][{self._model}][/bold green] ")

        full_text = ""
        try:
            async for chunk in self._api.async_chat_stream(
                model=self._model,
                messages=messages,
                chat_id=self._chat_id,
            ):
                log.write(chunk, expand=False)
                full_text += chunk
        except APIError as exc:
            self._history.pop()  # remove the user message that failed
            if exc.status_code == 403:
                log.write(
                    "\n[bold yellow]⚠ Session expired[/bold yellow] – "
                    "the server rejected your API key.\n"
                    "Exit the TUI and run [bold]fmind login[/bold] to authenticate again.\n"
                )
                self.app.notify(
                    "Your API key was rejected (403). Exit and run 'fmind login'.",
                    title="Session Expired",
                    severity="error",
                    timeout=0,
                )
                self.query_one(Input).disabled = True
            else:
                log.write(f"\n[red]Error {exc.status_code}:[/red] {exc}\n")
            return
        except Exception as exc:
            log.write(f"\n[red]Unexpected error:[/red] {exc}\n")
            self._history.pop()
            return

        log.write("\n")
        if full_text:
            self._history.append({"role": "assistant", "content": full_text})


# ── Main Menu Screen ───────────────────────────────────────────────────────────

class MainMenuScreen(Screen):
    """Arrow-key navigation main menu."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("q", "app.quit", "Quit"),
    ]

    CSS = """
    MainMenuScreen {
        align: center middle;
    }
    #menu-container {
        width: 52;
        height: auto;
        border: double $primary;
        padding: 1 2;
    }
    #welcome {
        text-align: center;
        color: $primary;
        text-style: bold;
        margin-bottom: 1;
    }
    #server-info {
        text-align: center;
        color: $text-muted;
        margin-bottom: 1;
    }
    ListView {
        height: auto;
        border: none;
    }
    ListItem {
        padding: 0 1;
    }
    ListItem:hover {
        background: $primary 20%;
    }
    ListItem.--highlight {
        background: $primary 30%;
    }
    """

    MENU: ClassVar[list[tuple[str, str]]] = [
        ("💬  Chat with AI", "chat"),
        ("🤖  Select Model", "models"),
        ("📜  Chat History", "history"),
        ("👤  Account", "account"),
        ("🔐  Logout", "logout"),
        ("❌  Exit", "exit"),
    ]

    def __init__(self, api: APIClient, username: str) -> None:
        super().__init__()
        self._api = api
        self._username = username

    def compose(self) -> ComposeResult:
        server = cfg.get_server_url() or ""
        model = cfg.get_default_model() or "–"
        with Container(id="menu-container"):
            yield Static("FactoryMind AI", id="welcome")
            yield Static(
                f"[dim]{self._username} @ {server}\nModel: {model}[/dim]",
                id="server-info",
            )
            yield ListView(
                *[ListItem(Label(label), id=action) for label, action in self.MENU]
            )
        yield Footer()

    def on_mount(self) -> None:
        self.query_one(ListView).focus()

    @on(ListView.Selected)
    def menu_selected(self, event: ListView.Selected) -> None:
        action = event.item.id
        if action == "exit":
            self.app.exit()
        elif action == "logout":
            cfg.clear_credentials()
            self.app.exit()
            from rich.console import Console
            Console().print("[yellow]Logged out.[/yellow]")
        elif action == "chat":
            model = cfg.get_default_model() or "Llama-2-7b-chat-hf"
            self.app.push_screen(ChatScreen(self._api, model))
        elif action == "models":
            self.app.push_screen(ModelSelectScreen(self._api))
        elif action == "history":
            self.app.push_screen(HistoryListScreen(self._api))
        elif action == "account":
            self._show_account()

    def _show_account(self) -> None:
        try:
            user = self._api.whoami()
            self.app.notify(
                f"User: {user['username']}\nEmail: {user['email']}\n"
                f"Key: {user['api_key'][:12]}…",
                title="Account",
                timeout=8,
            )
        except APIError as exc:
            self.app.notify(str(exc), title="Error", severity="error")


# ── History List Screen ────────────────────────────────────────────────────────

class HistoryListScreen(Screen):
    """Browse recent chat sessions."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("escape", "app.pop_screen", "Back"),
    ]

    CSS = """
    HistoryListScreen {
        align: center middle;
    }
    #hist-table {
        width: 90;
        height: 30;
        border: solid $primary;
    }
    #hist-hint {
        color: $text-muted;
        text-align: center;
        margin-top: 1;
    }
    """

    def __init__(self, api: APIClient) -> None:
        super().__init__()
        self._api = api

    def compose(self) -> ComposeResult:
        yield Header(show_clock=False)
        with Vertical():
            yield DataTable(id="hist-table", cursor_type="row")
            yield Static("Esc to go back", id="hist-hint")
        yield Footer()

    def on_mount(self) -> None:
        table = self.query_one(DataTable)
        table.add_columns("ID", "Title", "Model", "Updated")
        self._load_history()

    @work(thread=True)
    def _load_history(self) -> None:
        try:
            sessions = self._api.list_history(limit=30)
        except APIError:
            sessions = []
        self.call_from_thread(self._populate, sessions)

    def _populate(self, sessions: list[dict]) -> None:
        table = self.query_one(DataTable)
        table.clear()
        for s in sessions:
            updated = s["updated_at"][:16].replace("T", " ")
            table.add_row(
                s["id"][:8] + "…",
                s["title"],
                s["model_used"],
                updated,
                key=s["id"],
            )


# ── App ────────────────────────────────────────────────────────────────────────

class FactoryMindTUI(App):
    """Root Textual application."""

    TITLE = "FactoryMind AI"
    CSS = """
    Screen {
        background: $surface;
    }
    """

    def __init__(self, api: APIClient, username: str) -> None:
        super().__init__()
        self._api = api
        self._username = username

    def on_mount(self) -> None:
        self.push_screen(MainMenuScreen(self._api, self._username))


def launch_tui() -> None:
    """Entry point – build API client then start the TUI."""
    api = _make_client()
    if api is None:
        from rich.console import Console
        Console().print(
            "[red]Not logged in.[/red] Run [bold]fmind login[/bold] first."
        )
        return

    from rich.console import Console as _Console
    _con = _Console()

    try:
        user = api.whoami()
    except APIError as exc:
        if exc.status_code == 403:
            _con.print(
                "[bold yellow]⚠  Session expired[/bold yellow] – "
                "the server rejected your stored API key.\n"
                "Run [bold]fmind login[/bold] to authenticate again."
            )
        else:
            _con.print(f"[red]Cannot reach server:[/red] {exc}")
        return

    username = user.get("username", "unknown")
    FactoryMindTUI(api, username).run()

"""HTTP client wrapper for the FactoryMind API.

Free functions (register, login, whoami, …) are kept for backward-compat.
New code should use the APIClient class.
"""

import json
from typing import Any, AsyncIterator, Iterator, Optional

import httpx

from client import config as cfg


class APIError(Exception):
    def __init__(self, status_code: int, detail: str) -> None:
        self.status_code = status_code
        super().__init__(f"[{status_code}] {detail}")


def _raise_for(response: httpx.Response) -> None:
    if response.is_error:
        try:
            detail = response.json().get("detail", response.text)
        except Exception:
            detail = response.text
        raise APIError(response.status_code, detail)


# ── APIClient class ────────────────────────────────────────────────────────────

class APIClient:
    """Stateful client bound to a server URL + API key."""

    def __init__(self, server_url: str, api_key: str) -> None:
        self.server_url = server_url.rstrip("/")
        self.api_key = api_key
        self._headers = {"X-API-Key": api_key}

    # ── helpers ───────────────────────────────────────────────────────────────

    def _sync_client(self, timeout: float = 30.0) -> httpx.Client:
        return httpx.Client(
            base_url=self.server_url,
            headers=self._headers,
            timeout=timeout,
        )

    def _get(self, path: str, **params) -> dict:
        with self._sync_client() as c:
            r = c.get(path, params=params)
        _raise_for(r)
        return r.json()

    def _post(self, path: str, body: dict, timeout: float = 30.0) -> dict:
        with self._sync_client(timeout) as c:
            r = c.post(path, json=body)
        _raise_for(r)
        return r.json()

    # ── auth ──────────────────────────────────────────────────────────────────

    def whoami(self) -> dict:
        return self._get("/auth/me")

    def rotate_key(self) -> dict:
        return self._post("/auth/rotate-key", {})

    # ── models ────────────────────────────────────────────────────────────────

    def list_models(self) -> list[dict]:
        return self._get("/v1/models").get("data", [])

    def load_model(self, model_name: str) -> dict:
        return self._post(f"/v1/models/{model_name}/load", {})

    # ── chat (sync streaming – for CLI) ──────────────────────────────────────

    def chat(
        self,
        model: str,
        messages: list[dict],
        chat_id: Optional[str] = None,
        **kwargs,
    ) -> dict:
        """Non-streaming chat; returns the full OpenAI-style response."""
        body = {
            "model": model,
            "messages": messages,
            "stream": False,
            **kwargs,
        }
        if chat_id:
            body["chat_id"] = chat_id
        # Long timeout: model may need to load first
        return self._post("/v1/chat/completions", body, timeout=300.0)

    def chat_stream(
        self,
        model: str,
        messages: list[dict],
        chat_id: Optional[str] = None,
        **kwargs,
    ) -> Iterator[str]:
        """Sync generator that yields text chunks as they stream in.

        Raises APIError on non-200 responses.
        """
        body: dict[str, Any] = {
            "model": model,
            "messages": messages,
            "stream": True,
            **kwargs,
        }
        if chat_id:
            body["chat_id"] = chat_id

        with httpx.Client(
            base_url=self.server_url,
            headers=self._headers,
            timeout=300.0,
        ) as client:
            with client.stream(
                "POST", "/v1/chat/completions", json=body
            ) as response:
                if response.is_error:
                    response.read()
                    _raise_for(response)
                for line in response.iter_lines():
                    if not line or not line.startswith("data: "):
                        continue
                    data = line[6:]
                    if data.strip() == "[DONE]":
                        break
                    try:
                        chunk = json.loads(data)
                        delta = (
                            chunk["choices"][0]["delta"].get("content") or ""
                        )
                        if delta:
                            yield delta
                    except (json.JSONDecodeError, KeyError, IndexError):
                        continue

    # ── chat (async streaming – for TUI) ─────────────────────────────────────

    async def async_chat_stream(
        self,
        model: str,
        messages: list[dict],
        chat_id: Optional[str] = None,
        **kwargs,
    ) -> AsyncIterator[str]:
        """Async generator that yields text chunks. Used by the Textual TUI."""
        body: dict[str, Any] = {
            "model": model,
            "messages": messages,
            "stream": True,
            **kwargs,
        }
        if chat_id:
            body["chat_id"] = chat_id

        async with httpx.AsyncClient(
            base_url=self.server_url,
            headers=self._headers,
            timeout=300.0,
        ) as client:
            async with client.stream(
                "POST", "/v1/chat/completions", json=body
            ) as response:
                async for line in response.aiter_lines():
                    if not line or not line.startswith("data: "):
                        continue
                    data = line[6:]
                    if data.strip() == "[DONE]":
                        break
                    try:
                        chunk = json.loads(data)
                        delta = (
                            chunk["choices"][0]["delta"].get("content") or ""
                        )
                        if delta:
                            yield delta
                    except (json.JSONDecodeError, KeyError, IndexError):
                        continue

    # ── history ───────────────────────────────────────────────────────────────

    def list_history(self, limit: int = 20) -> list[dict]:
        return self._get("/v1/history", limit=limit)

    def get_chat(self, chat_id: str) -> dict:
        return self._get(f"/v1/history/{chat_id}")

    # ── health ────────────────────────────────────────────────────────────────

    def health(self) -> dict:
        with httpx.Client(base_url=self.server_url, timeout=10.0) as c:
            r = c.get("/health")
        _raise_for(r)
        return r.json()


# ── Convenience factory ────────────────────────────────────────────────────────

def get_client() -> APIClient:
    """Build an APIClient from the local config file. Raises if not logged in."""
    url = cfg.get_server_url()
    key = cfg.get_api_key()
    if not url or not key:
        raise APIError(0, "Not logged in. Run `fmind login` first.")
    return APIClient(url, key)


# ── Legacy module-level functions (kept for auth command) ─────────────────────

def _mk(server_url: str, api_key: Optional[str] = None) -> httpx.Client:
    headers = {"X-API-Key": api_key} if api_key else {}
    return httpx.Client(base_url=server_url, headers=headers, timeout=30.0)


def register(
    server_url: str, username: str, email: str, password: str
) -> dict[str, Any]:
    with _mk(server_url) as c:
        r = c.post(
            "/auth/register",
            json={"username": username, "email": email, "password": password},
        )
    _raise_for(r)
    return r.json()


def login(server_url: str, username: str, password: str) -> dict[str, Any]:
    with _mk(server_url) as c:
        r = c.post("/auth/login", json={"username": username, "password": password})
    _raise_for(r)
    return r.json()


def whoami(server_url: str, api_key: str) -> dict[str, Any]:
    with _mk(server_url, api_key) as c:
        r = c.get("/auth/me")
    _raise_for(r)
    return r.json()


def rotate_key(server_url: str, api_key: str) -> dict[str, Any]:
    with _mk(server_url, api_key) as c:
        r = c.post("/auth/rotate-key")
    _raise_for(r)
    return r.json()


def health(server_url: str) -> dict[str, Any]:
    with httpx.Client(base_url=server_url, timeout=10.0) as c:
        r = c.get("/health")
    _raise_for(r)
    return r.json()

