"""fmind chat – interactive and one-shot chat with streaming."""

import os
import sys
from typing import Optional

import typer
from rich.console import Console
from rich.markdown import Markdown
from rich.panel import Panel
from rich.rule import Rule
from rich.text import Text

import client.api as fmapi
from client import config as cfg
from client.api import APIClient, APIError, get_client

console = Console()
app = typer.Typer(help="Chat with an LLM.")

_SLASH_COMMANDS = "[dim]Commands: /models · /switch <model> · /clear · /history · /exit[/dim]"


# ── Internal signal ────────────────────────────────────────────────────────────

class _SessionExpired(Exception):
    """Raised by _stream_response when the server returns 403."""


# ── Helpers ───────────────────────────────────────────────────────────────────

def _relogin(server_url: str) -> Optional[APIClient]:
    """Interactive re-login prompt. Returns a new APIClient or None if user declines."""
    console.print(
        "\n[bold yellow]⚠  Session expired[/bold yellow] – "
        "the server rejected your API key (403 Forbidden).\n"
        "You need to log in again to continue.\n"
    )
    if not typer.confirm("Log in now?", default=True):
        console.print("[dim]Run [bold]fmind login[/bold] when ready.[/dim]")
        return None

    username = typer.prompt("Username")
    password = typer.prompt("Password", hide_input=True)
    try:
        user = fmapi.login(server_url, username, password)
        cfg.save_credentials(server_url, user["api_key"])
        console.print(f"[green]✓ Logged in as[/green] [bold]{user['username']}[/bold]\n")
        return APIClient(server_url, user["api_key"])
    except APIError as exc:
        console.print(f"[red]Login failed:[/red] {exc}")
        return None


def _pick_model(api: APIClient, requested: Optional[str]) -> str:
    """Return the model to use: explicit arg > config default > first in catalog."""
    if requested:
        return requested
    default = cfg.get_default_model()
    if default:
        return default
    try:
        models = api.list_models()
        if models:
            return models[0]["id"]
    except APIError:
        pass
    return "Llama-2-7b-chat-hf"


def _print_models_table(api: APIClient) -> None:
    from rich.table import Table

    try:
        models = api.list_models()
    except APIError as exc:
        if exc.status_code == 403:
            console.print("[yellow]⚠ Session expired.[/yellow] Run [bold]fmind login[/bold].")
        else:
            console.print(f"[red]Could not fetch models:[/red] {exc}")
        return

    table = Table(title="Available Models", show_lines=False)
    table.add_column("ID", style="bold cyan", no_wrap=True)
    table.add_column("Description")
    table.add_column("Cached", justify="center")
    table.add_column("Loaded", justify="center")

    for m in models:
        table.add_row(
            m["id"],
            m.get("description", ""),
            "✓" if m.get("cached") else "–",
            "[green]●[/green]" if m.get("loaded") else "○",
        )
    console.print(table)


def _stream_response(api: APIClient, model: str, messages: list) -> str:
    """Send messages, stream the response to terminal. Returns full text.

    Raises _SessionExpired if the server returns 403.
    """
    console.print()
    label = Text(f"[{model}] ", style="bold green")
    console.print(label, end="")

    full = ""
    first = True

    with console.status(
        f"[dim]Loading {model}… (first load may take a few minutes)[/dim]",
        spinner="dots",
    ) as status:
        try:
            for chunk in api.chat_stream(model=model, messages=messages):
                if first:
                    status.stop()
                    first = False
                console.print(chunk, end="", highlight=False, markup=False)
                full += chunk
        except APIError as exc:
            if first:
                status.stop()
            if exc.status_code == 403:
                raise _SessionExpired()
            console.print(f"\n[red]Error {exc.status_code}:[/red] {exc}")
            return ""
        except KeyboardInterrupt:
            if first:
                status.stop()
            console.print("\n[yellow]Interrupted.[/yellow]")
            return full

    console.print()
    return full


# ── Commands ──────────────────────────────────────────────────────────────────

@app.command()
def chat(
    model: Optional[str] = typer.Option(
        None, "--model", "-M", help="Model to use (e.g. Llama-2-7b-chat-hf)."
    ),
    message: Optional[str] = typer.Option(
        None, "--message", "-m", help="One-shot prompt; exits after responding."
    ),
):
    """Chat interactively with an LLM, or ask a single question with -m."""
    try:
        api = get_client()
    except APIError as exc:
        console.print(f"[red]{exc}[/red]")
        raise typer.Exit(1)

    # ── Validate session before doing anything ────────────────────────────────
    try:
        api.whoami()
    except APIError as exc:
        if exc.status_code == 403:
            new_api = _relogin(api.server_url)
            if not new_api:
                raise typer.Exit(1)
            api = new_api
        else:
            console.print(f"[red]Cannot reach server:[/red] {exc}")
            raise typer.Exit(1)

    current_model = _pick_model(api, model)

    # ── One-shot mode ─────────────────────────────────────────────────────────
    if message:
        messages = [{"role": "user", "content": message}]
        try:
            response = _stream_response(api, current_model, messages)
        except _SessionExpired:
            console.print(
                "\n[bold yellow]⚠ Session expired[/bold yellow] – "
                "run [bold]fmind login[/bold] and try again."
            )
            raise typer.Exit(1)
        if response:
            console.print(Rule(style="dim"))
            console.print(Markdown(response))
        return

    # ── Interactive mode ──────────────────────────────────────────────────────
    server_url = cfg.get_server_url()
    console.print(
        Panel(
            f"[bold]FactoryMind AI[/bold]\n"
            f"Server: [dim]{server_url}[/dim]\n"
            f"Model:  [cyan]{current_model}[/cyan]\n\n"
            + _SLASH_COMMANDS,
            expand=False,
        )
    )

    history: list[dict] = []

    while True:
        try:
            user_input = console.input(
                f"\n[bold blue]\\[{current_model}] You:[/bold blue] "
            ).strip()
        except (EOFError, KeyboardInterrupt):
            console.print("\n[yellow]Goodbye![/yellow]")
            break

        if not user_input:
            continue

        # ── Slash commands ────────────────────────────────────────────────────
        if user_input.startswith("/"):
            parts = user_input.split(maxsplit=1)
            cmd = parts[0].lower()

            if cmd in ("/exit", "/quit", "/q"):
                console.print("[yellow]Goodbye![/yellow]")
                break

            elif cmd == "/clear":
                os.system("clear" if sys.platform != "win32" else "cls")
                history.clear()
                console.print("[dim]Screen cleared. History reset.[/dim]")

            elif cmd == "/models":
                _print_models_table(api)

            elif cmd == "/switch":
                if len(parts) < 2:
                    console.print("[red]Usage:[/red] /switch <model-name>")
                else:
                    current_model = parts[1].strip()
                    history.clear()
                    cfg.save_default_model(current_model)
                    console.print(
                        f"[green]Switched to[/green] [cyan]{current_model}[/cyan]. "
                        "History cleared."
                    )

            elif cmd == "/history":
                if not history:
                    console.print("[dim]No messages yet.[/dim]")
                else:
                    for msg in history:
                        role = "You" if msg["role"] == "user" else current_model
                        style = "blue" if msg["role"] == "user" else "green"
                        console.print(f"[{style}]{role}:[/{style}] {msg['content']}")

            else:
                console.print(
                    f"[yellow]Unknown command:[/yellow] {cmd}\n" + _SLASH_COMMANDS
                )
            continue

        # ── Normal message ────────────────────────────────────────────────────
        history.append({"role": "user", "content": user_input})
        try:
            response = _stream_response(api, current_model, history)
        except _SessionExpired:
            history.pop()  # remove the unsent user message
            new_api = _relogin(api.server_url)
            if new_api:
                api = new_api
                console.print(
                    "[dim]Session renewed – please re-send your last message.[/dim]"
                )
            else:
                break
            continue

        if response:
            history.append({"role": "assistant", "content": response})

"""Textual-based interactive TUI for FactoryMind AI.

Launch with: fmind tui  (or just: fmind  when already logged in)
"""

from __future__ import annotations

from typing import ClassVar, Optional

from textual import on, work
from textual.app import App, ComposeResult
from textual.binding import Binding
from textual.containers import Container, Horizontal, Vertical
from textual.screen import Screen
from textual.widgets import (
    DataTable,
    Footer,
    Header,
    Input,
    Label,
    ListItem,
    ListView,
    RichLog,
    Static,
)

from client import config as cfg
from client.api import APIClient, APIError, get_client


# ── Helpers ────────────────────────────────────────────────────────────────────

def _make_client() -> Optional[APIClient]:
    try:
        return get_client()
    except APIError:
        return None


# ── Model Select Screen ────────────────────────────────────────────────────────

class ModelSelectScreen(Screen):
    """Pick a default model from the server catalog."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("escape", "app.pop_screen", "Back"),
    ]

    CSS = """
    ModelSelectScreen {
        align: center middle;
    }
    #model-table {
        width: 80;
        height: auto;
        border: solid $primary;
    }
    #model-hint {
        color: $text-muted;
        text-align: center;
        margin-top: 1;
    }
    """

    def __init__(self, api: APIClient) -> None:
        super().__init__()
        self._api = api

    def compose(self) -> ComposeResult:
        yield Header(show_clock=False)
        with Vertical():
            yield DataTable(id="model-table", cursor_type="row")
            yield Static("Enter to select · Esc to go back", id="model-hint")
        yield Footer()

    def on_mount(self) -> None:
        table = self.query_one(DataTable)
        table.add_columns("Model", "Description", "Cached", "Loaded")
        self._load_models()

    @work(thread=True)
    def _load_models(self) -> None:
        try:
            models = self._api.list_models()
        except APIError:
            models = []
        self.app.call_from_thread(self._populate_table, models)

    def _populate_table(self, models: list[dict]) -> None:
        table = self.query_one(DataTable)
        table.clear()
        for m in models:
            table.add_row(
                m["id"],
                m.get("description", ""),
                "✓" if m.get("cached") else "–",
                "● loaded" if m.get("loaded") else "○",
                key=m["id"],
            )

    @on(DataTable.RowSelected)
    def row_selected(self, event: DataTable.RowSelected) -> None:
        model_id = str(event.row_key.value)
        cfg.save_default_model(model_id)
        self.app.pop_screen()
        self.app.notify(f"Default model set to {model_id}", title="Model selected")


# ── Chat Screen ────────────────────────────────────────────────────────────────

class ChatScreen(Screen):
    """Full interactive chat with streaming responses."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("ctrl+c", "app.pop_screen", "Back", show=False),
        Binding("escape", "app.pop_screen", "Back"),
        Binding("ctrl+l", "clear_history", "Clear"),
    ]

    CSS = """
    ChatScreen {
        layout: vertical;
    }
    #messages {
        height: 1fr;
        border: solid $primary;
        overflow-y: auto;
        padding: 0 1;
    }
    #input-row {
        height: 3;
        layout: horizontal;
    }
    #chat-input {
        width: 1fr;
    }
    #model-label {
        color: $success;
        padding: 0 1;
        content-align: center middle;
        height: 3;
    }
    """

    def __init__(self, api: APIClient, model: str) -> None:
        super().__init__()
        self._api = api
        self._model = model
        self._history: list[dict] = []
        self._chat_id: Optional[str] = None

    def compose(self) -> ComposeResult:
        yield Header(show_clock=True)
        yield RichLog(id="messages", highlight=True, markup=True, wrap=True)
        with Horizontal(id="input-row"):
            yield Label(f"[{self._model}]", id="model-label")
            yield Input(placeholder="Type a message… (Esc = back)", id="chat-input")
        yield Footer()

    def on_mount(self) -> None:
        log = self.query_one(RichLog)
        log.write(
            f"[dim]Chat started with [bold]{self._model}[/bold]. "
            "Type a message and press Enter.[/dim]\n"
        )
        self.query_one(Input).focus()

    @on(Input.Submitted)
    def on_input_submitted(self, event: Input.Submitted) -> None:
        text = event.value.strip()
        if not text:
            return
        event.input.clear()

        log = self.query_one(RichLog)
        log.write(f"\n[bold blue]You:[/bold blue] {text}\n")

        self._history.append({"role": "user", "content": text})
        self._stream_response(list(self._history))

    def action_clear_history(self) -> None:
        self._history.clear()
        self._chat_id = None
        self.query_one(RichLog).clear()
        self.query_one(RichLog).write("[dim]History cleared.[/dim]\n")

    @work(exclusive=False)
    async def _stream_response(self, messages: list[dict]) -> None:
        log = self.query_one(RichLog)
        log.write(f"\n[bold green][{self._model}][/bold green] ")

        full_text = ""
        try:
            async for chunk in self._api.async_chat_stream(
                model=self._model,
                messages=messages,
                chat_id=self._chat_id,
            ):
                log.write(chunk, expand=False)
                full_text += chunk
        except APIError as exc:
            self._history.pop()  # remove the user message that failed
            if exc.status_code == 403:
                log.write(
                    "\n[bold yellow]⚠ Session expired[/bold yellow] – "
                    "the server rejected your API key.\n"
                    "Exit the TUI and run [bold]fmind login[/bold] to authenticate again.\n"
                )
                self.app.notify(
                    "Your API key was rejected (403). Exit and run 'fmind login'.",
                    title="Session Expired",
                    severity="error",
                    timeout=0,
                )
                self.query_one(Input).disabled = True
            else:
                log.write(f"\n[red]Error {exc.status_code}:[/red] {exc}\n")
            return
        except Exception as exc:
            log.write(f"\n[red]Unexpected error:[/red] {exc}\n")
            self._history.pop()
            return

        log.write("\n")
        if full_text:
            self._history.append({"role": "assistant", "content": full_text})


# ── Main Menu Screen ───────────────────────────────────────────────────────────

class MainMenuScreen(Screen):
    """Arrow-key navigation main menu."""

    BINDINGS: ClassVar[list[Binding]] = [
        Binding("q", "app.quit", "Quit"),
    ]

    CSS = """
    MainMenuScreen {
        align: center middle;
    }
    #menu-container {
        width: 52;
        height: auto;
        border: double $primary;
        padding: 1 2;
    }
    #welcome {
        text-align: center;
        color: $primary;
        text-style: bold;
        margin-bottom: 1;
    }
    #server-info {
        text-align: center;
        color: $text-muted;
        margin-bottom: 1;
    }
    ListView {
        height: auto;
        border: none;
    }
    ListItem {
        padding: 0 1;
    }
    ListItem:hover {
        background: $primary 20%;
    }
    ListItem.--highlight {
        background: $primary 30%;
    }
    """

    MENU: ClassVar[list[tuple[str, str]]] = [
        ("💬  Chat with AI", "chat"),
        ("🤖  Select Model", "models"),
        ("📜  Chat History", "history"),
        ("👤  Account", "account"),
        ("🔐  Logout", "logout"),
        ("❌  Exit", "exit"),
    ]

    def __init__(self, api: APIClient, username: str) -> None:
        super().__init__()
        self._api = api
        self._username = username

    def compose(self) -> ComposeResult:
        server = cfg.get_server_url() or ""
        model = cfg.get_default_model() or "–"
        with Container(id="menu-container"):
            yield Static("FactoryMind AI", id="welcome")
            yield Static(
                f"[dim]{self._username} @ {server}\nModel: {model}[/dim]",
                id="server-info",
            )
            yield ListView(
                *[ListItem(Label(label), id=action) for label, action in self.MENU]
            )
        yield Footer()

    def on_mount(self) -> None:
        self.query_one(ListView).focus()

    @on(ListView.Selected)
    def menu_selected(self, event: ListView.Selected) -> None:
        action = event.item.id
        if action == "exit":
            self.app.exit()
        elif action == "logout":
            cfg.clear_credentials()
            self.app.exit()
            from rich.console import Console
            Console().print("[yellow]Logged out.[/yellow]")
        elif action == "chat":
            model = cfg.get_default_model() or "Llama-2-7b-chat-hf"
            self.app.push_screen(ChatScreen(self._api, model))
        elif action == "models":
            self.app.push_screen(ModelSelectScreen(self._api))
        elif action == "history":
            self.app.push_screen(HistoryListScreen(self._api))
        elif action == "account":
            self._show_account()

    def _show_account(self) -> None:
        try:
