        padding: 0 1;
    }
    ListItem:hover {
        background: $primary 20%;
    }
    ListItem.--highlight {
        background: $primary 30%;
    }
    """

    MENU: ClassVar[list[tuple[str, str]]] = [
        ("💬  Chat with AI", "chat"),
        ("🤖  Select Model", "models"),
        ("📜  Chat History", "history"),
        ("👤  Account", "account"),
        ("🔐  Logout", "logout"),
        ("❌  Exit", "exit"),
    ]

    def __init__(self, api: APIClient, username: str) -> None:
        super().__init__()
        self._api = api
        self._username = username

    def compose(self) -> ComposeResult:
        server = cfg.get_server_url() or ""
        model = cfg.get_default_model() or "–"
        with Container(id="menu-container"):
            yield Static("FactoryMind AI", id="welcome")
            yield Static(
                f"[dim]{self._username} @ {server}\nModel: {model}[/dim]",
                id="server-info",
            )
            yield ListView(
                *[ListItem(Label(label), id=action) for label, action in self.MENU]
            )
        yield Footer()

    def on_mount(self) -> None:
        self.query_one(ListView).focus()

    @on(ListView.Selected)
    def menu_selected(self, event: ListView.Selected) -> None:
        action = event.item.id
        if action == "exit":
            self.app.exit()
        elif action == "logout":
            cfg.clear_credentials()
            self.app.exit()
            from rich.console import Console
            Console().print("[yellow]Logged out.[/yellow]")
        elif action == "chat":
            model = cfg.get_default_model() or "Llama-2-7b-chat-hf"
            self.app.push_screen(ChatScreen(self._api, model))
        elif action == "models":
            self.app.push_screen(ModelSelectScreen(self._api))
        elif action == "history":
            self.app.push_screen(HistoryListScreen(self._api))
        elif action == "account":
            self._show_account()

    def _show_account(self) -> None:
        try:
            user = self._api.whoami()
            self.app.notify(
                f"User: {user['username']}\nEmail: {user['email']}\n"
                f"Key: {user['api_key'][:12]}…",
                title="Account",
                timeout=8,
            )
        except APIError as exc:
            self.app.notify(str(exc), title="Error", severity="error")


